as ) self . _novelty = float ( novelty ) except ( TypeError , ValueError ) as exception : exception . add_note ( f "fitness: { fitness } " ) exception . add_note ( f "performance_bias: { performance_bias } " ) exception . add_note ( f "novelty: { novelty } " ) raise TypeError ( "Wrong parameters for Instance." ) from exception # Todo: Consider fix the dimensions of the descriptor and portfolio # if type(descriptor_dim) is not int or descriptor_dim <= 0: # raise ValueError( # f"descriptor_dim must be a positive integer. Got {descriptor_dim}." # ) # else: # self._descriptor_dim = int(descriptor_dim) # if type(portfolio_dim) is not int or portfolio_dim <= 0: # raise ValueError( # f"portfolio_dim must be a positive integer. Got {portfolio_dim}." # ) # else: # self._portfolio_dim = int(portfolio_dim) if variables is None or len ( variables ) == 0 : raise ValueError ( f "variables has to be a valid sequence. Got: { variables } " ) else : self . _variables = np . asarray ( variables , dtype = self . _dtype , copy = True ) if descriptor is not None and len ( descriptor ) == 0 : raise ValueError ( f "descriptors must be either None or a sequence with at least one value. Got: { descriptor } " ) else : if descriptor is None : self . _descriptor = np . empty ( 0 , dtype = np . float64 ) else : self . _descriptor = np . asarray ( descriptor , dtype = np . float64 , copy = True ) if portfolio_scores is not None and len ( portfolio_scores ) == 0 : raise ValueError ( f "portfolio_scores must be either None or a sequence with at least one value. Got: { portfolio_scores } " ) else : if portfolio_scores is None : self . _portfolio_scores = np . empty (( 0 ), dtype = np . float64 ) else : self . _portfolio_scores = np . asarray ( portfolio_scores , dtype = np . float64 ) @property def dtype ( self ): return self . _dtype def clone ( self ) -> Self : """Create a clone of the current instance. This avoids Python-level list/tuple conversions by copying the underlying NumPy arrays directly. Returns: Self: Instance object """ new_instance = object . __new__ ( type ( self )) new_instance . _dtype = self . _dtype new_instance . _fitness = self . _fitness new_instance . _performance_bias = self . _performance_bias new_instance . _novelty = self . _novelty new_instance . _variables = self . _variables . copy () new_instance . _descriptor = self . _descriptor . copy () new_instance . _portfolio_scores = self . _portfolio_scores . copy () return new_instance def clone_with ( self , ** overrides ): """Clones an Instance with overriden attributes Returns: Instance """ new_object = self . clone () for key , value in overrides . items (): setattr ( new_object , key , value ) return new_object @property def variables ( self ): return self . _variables @variables . setter def variables ( self , new_variables : np . ndarray ): if new_variables is None or len ( new_variables ) == 0 : raise ValueError ( f "new_variables cannot be None nor be empty. Got: { new_variables } ." ) elif len ( new_variables ) != len ( self . _variables ): raise ValueError ( "Updating the variables of an Instance object with a different number of values. " f "Instance have { len ( self . _variables ) } variables " f "and the new_variables sequence have { len ( new_variables ) } " ) else : self . _variables = np . asarray ( new_variables ) @property def performance_bias ( self ) -> float | np . float64 : return self . _performance_bias @performance_bias . setter def performance_bias ( self , performance : float | np . float64 ): try : self . _performance_bias = float ( performance ) except ( TypeError , ValueError ) as exc : raise ValueError ( f "performance_bias value is not a float. Got: { performance } ." ) from exc @property def novelty ( self ) -> float | np . float64 : return self . _novelty @novelty . setter def novelty ( self , nov_score : float | np . float64 ): try : self . _novelty = float ( nov_score ) except ( TypeError , ValueError ) as exc : raise ValueError ( f "nov_score value is not a float. Got: { nov_score } ." ) from exc @property def fitness ( self ) -> float | np . float64 : return self . _fitness @fitness . setter def fitness ( self , new_fitness : float | np . float64 ): try : self . _fitness = float ( new_fitness ) except ( TypeError , ValueError ) as exc : raise ValueError ( f "new_fitness value is not a float. Got: { new_fitness } ." ) from exc @property def descriptor ( self ) -> np . ndarray : return self . _descriptor @descriptor . setter def descriptor ( self , descriptor : Sequence [ float | np . float64 ] | np . ndarray ): self . _descriptor = np . asarray ( descriptor ) @property def portfolio_scores ( self ): return self . _portfolio_scores @portfolio_scores . setter def portfolio_scores ( self , scores : Sequence [ float | np . float64 ] | np . ndarray ): self . _portfolio_scores = np . asarray ( scores ) def __repr__ ( self ): return self . __str__ () def __str__ ( self ): import reprlib descriptor = reprlib . repr ( self . descriptor ) performance = reprlib . repr ( self . portfolio_scores ) performance = performance [ performance . find ( "(" ) : performance . rfind ( ")" ) + 1 ] return ( f "Instance: 
