 " ) def __iter__ ( self ): return iter ( self . _variables ) def __len__ ( self ): return len ( self . _variables ) def __getitem__ ( self , key : int | slice ) -> Sequence | np . ndarray : """Accessor to variables of the Instance Args: key (index | slice): index or slice to access a subset of variables Returns: Sequence or np.ndarray: If accessed with a slice the subset of variables are returned. Otherwise, it returns a single scalar at variables[key]. """ if not isinstance ( key , ( int , slice )): raise TypeError ( f "Instance cannot be indexed with type: { type ( key ) } . Use slice or int." ) if isinstance ( key , slice ): return self . _variables [ key ] else : index = operator . index ( key ) return self . variables [ index ] def __setitem__ ( self , key : int | slice , value ): """Setter to variables of the Instance Args: key (int | slice): index or slice to access a subset of variables value: Value to set in the variables """ if not isinstance ( key , ( int , np . integer , np . unsignedinteger , slice )): raise TypeError ( f "Instance cannot be update via __setitem__ with type: { type ( key ) } . Use slice or int." ) if isinstance ( key , slice ): # Compute how many positions this slice actually targets start , stop , step = key . indices ( len ( self . variables )) target_count = len ( range ( start , stop , step )) # Accept any sequence; reject bare scalars for slice assignment try : expected_len = len ( value ) except TypeError : raise TypeError ( f "[Instance] slice assignment requires a sequence, got scalar { value !r} . " f "Expected { target_count } value(s)." ) if expected_len != target_count : raise ValueError ( f "[Instance] slice targets { target_count } element(s) but value has " f " { expected_len } element(s)." ) else : index = operator . index ( key ) try : if len ( value ) != 1 : raise ValueError ( f "[Instance] index { index !r} targets 1 element but value has " f " { len ( value ) } element(s). Use a slice to assign multiple values." ) except TypeError : pass # len() failed which means that we have a scalar value self . _variables [ key ] = value def __eq__ ( self , other : Self ) -> bool : """Compares two Instances based on their variables. Args: other (Self): Another instance to compare. Returns: bool: Returns True if the two instances have the same number of variables, and all of them are equal. Returns False otherwise. """ if not isinstance ( other , Instance ): raise TypeError ( f "Other of type { other . __class__ . __name__ } can not be compared with an Instance." ) else : try : return all ( a == b for a , b in zip ( self , other , strict = True )) except ValueError : return False def __gt__ ( self , other : Self ) -> bool | np . bool : """Compares two Instances based on their fitness. Args: other (Self): Another instance to compare. Returns: bool: Returns True if the self has a greater fitness than the other. Returns False otherwise. """ if not isinstance ( other , Instance ): raise TypeError ( f "Other of type { other . __class__ . __name__ } can not be compared with an Instance." ) else : return self . fitness > other . fitness def __ge__ ( self , other : Self ) -> bool | np . bool : """Compares two Instances based on their fitness. Args: other (Self): Another instance to compare. Returns: bool: Returns True if the self has a greater or equal fitness than the other. Returns False otherwise. """ if not isinstance ( other , Instance ): raise TypeError ( f "Other of type { other . __class__ . __name__ } can not be compared with an Instance." ) else : return self . fitness >= other . fitness def to_dict ( self , variables_names : Optional [ Sequence [ str ]] = None , descriptor_names : Optional [ Sequence [ str ]] = None , portfolio_names : Optional [ Sequence [ str ]] = None , ) -> dict : """Convert the instance to a dictionary. The keys are the names of the attributes and the values are the values of the attributes. Args: variables_names (Optional[Sequence[str]], optional): Names of the variables in the dictionary, otherwise v_i. Defaults to None. descriptor_names: (Optional[Sequence[str]], optional): Names of the components of the descriptor, otherwisde di. Default to None. portfolio_names (Optional[Sequence[str]], optional): Name of the solvers, otherwise solver_i. Defaults to None. Returns: dict: Dictionary with the attributes of the instance as keys and the values of the attributes as values. """ _instance_data = {} descriptor_names = _validate_column_names ( "descriptor" , descriptor_names , len ( self . _descriptor ), fallback_keyword = "d" ) _instance_data = { ** { key : value for key , value in zip ( descriptor_names , self . _descriptor )} } variables_names = _validate_column_names ( "variables_names" , variables_names , len ( self ), fallback_keyword = "v" ) _instance_data [ "variables" ] = { key : value for key , value in zip ( variables_names , self . _variables ) } portfolio_names = _validate_column_names ( "portfolio_names" , portfolio_names , len ( self . portfolio_scores ), fallback_keyword = "alg" , ) _instance_data [ "portfolio_scores" ] = { key : value for key , value in zip ( portfolio_names , self . _portfolio_scores ) } _instance_data = { "target" : portfolio_names [ 0 ], "fitness" : self . _fitness , "novelty" : self . _novelty , "performance_bias" : self . _performance_bias , ** _instance_data , } return _instance_data def to_json ( self ) -> str : """Convert the instance to a JSON string. The keys are the names of the attributes and the values are the values of the attributes. Returns: str: JSON string with the attributes of the instance as keys and the values of the attributes as values. """ import json # Todo: Need to change dtypes because np is not JSON serializable return json . dumps ( self . to_dict (), sort_keys = False , indent = 2 ) def to_df ( self , variables_names : Optional [ Sequence [ str ]] = None , descriptor_names : Optional [ Sequence [ str ]] = None , portfolio_names : Optional [ Sequence [ str ]] = None , ) -> pl . DataFrame : """Creates a Polars DataFrame from the instance. Args: variables_names (Optional[Sequence[str]], optional): Names of the variables in the dictionary, otherwise v_i. Defaults to None. descriptor_names: (Optional[Sequence[str]], optional): Names of the components of the descriptor, otherwisde di. Default to None. portfolio_names (Optional[Sequence[str]], optional): Name of the solvers, otherwise solver_i. Defaults to None. Returns: DataFrame: Polars DataFrame with the attributes of the instance as keys and the values of the attributes as values. """ _flatten_data = {} for key , value in self . to_dict ( variables_names = variables_names , descriptor_names = descriptor_names , portfolio_names = portfolio_names , ) . items (): if isinstance ( value , dict ): # Flatten nested dicts for sub_key , sub_value in value . items (): _flatten_data [ sub_key ] = sub_value else : _flatten_data [ key ] = value return pl . DataFrame ( _flatten_data ) __eq__ ( other ) Compares two Instances based on their variables. Parameters: other ( Self ) – Another instance to compare. Returns: bool ( bool ) – Returns True if the two instances have the same number of variables, bool – and all of them are equal. Returns False otherwise. Source code in digneapy/core/_instance.py 347 348 349 350 351 352 353 354 355 356 357 358 359 360 361 362 363 364 365 366 def __eq__ ( self , other : Self ) -> bool : """Compares two Instances based on their variables. Args: other (Self): Another instance to compare. Returns: bool: Returns True if the two instances have the same number of variables, and all of them are equal. Returns False otherwise. """ if not isinstance ( other , Instance ): raise TypeError ( f "Other of type { other . __class__ . __name__ } can not be compared with an Instance." ) else : try : return all ( a == b for a , b in zip ( self , other , strict = True )) except ValueError : return False __ge__ ( other ) Compares two Instances based on their fitness. Parameters: oth