io ) / used_bins try : # We asume that individual is a Solution object # Therefore, it must have a fitness and objective attributes # Otherwise, we got sequence/ndarray and we just return the fitness individual . fitness = fitness individual . objectives = ( fitness ,) except Exception : return ( fitness ,) return ( fitness ,) def __call__ ( self , individual : Sequence | Solution | np . ndarray ) -> Tuple [ float ]: """Evaluates the candidate individual with the information of the Bin Packing. The fitness of the solution is the amount of unused space, as well as the number of bins for a specific solution. Falkenauer (1998) performance metric defined as: (x) = \frac{\sum_{k=1}^{N} \left(\frac{fill_k}{C}\right)^2}{N} Args: individual (Sequence | Solution): Individual to evaluate Returns: Tuple[float]: Falkenauer Fitness """ return self . evaluate ( individual ) def __str__ ( self ): return f "BPP(n= { self . _dimension } ,C= { self . _maximum_capacity } ,I= { self . _items } )" def __len__ ( self ): return self . _dimension def __array__ ( self , dtype = np . int32 , copy : Optional [ bool ] = None ) -> np . ndarray : """Return a NumPy array representation of the Bin Packing Problem. The representation stores the capacity first and then all the items. Returns: np.ndarray: A one-dimensional array describing the instance. """ return np . asarray ( [ self . _maximum_capacity , * self . _items ], dtype = dtype , copy = copy ) def create_solution ( self ) -> Solution : """Creates a random BPP solution The solution is created with variables equal to [0, dimension]. Which means that each item is stored in a independent bin. Also, the number of objectives is set to 1. Returns: Solution: Initial valid solution. """ items = np . arange ( self . _dimension ) return Solution ( variables = items , objectives = np . zeros ( 1 ), ) def to_file ( self , filename : str | Path = "instance.bpp" ): """Saves the BPP problem to a file Args: filename (str | Path, optional): Name of the fil