/domains/bpp.py 375 376 377 378 379 380 381 382 383 384 385 386 387 388 389 390 391 392 393 394 395 396 397 398 399 400 401 402 403 404 def generate_instances ( self , n : np . uint32 = np . uint32 ( 1 )) -> Sequence [ Instance ]: """Generates N new instances for the BPP domain. Args: n (int, optional): Number of instances to generate. Defaults to 1. Returns: List[Instance]: A list of Instance objects created from the raw numpy generation """ # Dimension is set correctly to number_of_items + 1 to # allow the random generation of capacities instances = self . _rng . integers ( low = self . _minimum_weight , high = self . _maximum_weight , size = ( n , self . _dimension ), dtype = int , ) # Sets the capacity according to the method match self . capacity_approach : case "evolved" : instances [:, 0 ] = self . _rng . integers ( 1 , self . _max_capacity , size = n ) case "percentage" : instances [:, 0 ] = ( np . sum ( instances [:, 1 :], axis = 1 , dtype = np . int32 ) * self . _capacity_ratio ) case "fixed" : instances [:, 0 ] = self . _max_capacity return list ( Instance ( variables = i ) for i in instances ) generate_problems_from_instances ( instances ) Generates BPP problems from the given instances This method is used to generate a collection of (objects) of the BPP class ready to be solved from the definition of the instances. Parameters: instances ( Sequence [ Instance ] | ndarray ) – Instances to generate the problems from. Returns: List [ BPP ] – List[BPP]: List of BPP objects created from the instances Source code in digneapy/domains/bpp.py 485 486 487 488 489 490 491 492 493 494 495 496 497 498 499 500 501 502 503 504 505 506 507 508 509 510 511 512 513 514 515 516 517 518 519 520 def generate_problems_from_instances ( self , instances : Sequence [ Instance ] | np . ndarray ) -> List [ BPP ]: """Generates BPP problems from the given instances This method is used to generate a collection of (objects) of the BPP class ready to be solved from the definition of the instances. Args: instances (Sequence[Instance] | np.ndarray): Instances to generate the problems from. Returns: List[BPP]: List of BPP objects created from the instances """ if not isinstance ( instances , np . ndarray ): instances = np . asarray ( instances ) # Assume evolved capacities capacities = instances [:, 0 ] . astype ( np . int32 ) match self . capacity_approach : case "percentage" : capacities [:] = ( np . sum ( instances [:, 1 :], axis = 1 ) * self . _capacity_ratio ) . astype ( np . int32 ) instances [:, 0 ] = capacities [:] case "fixed" : capacities [:] = self . _max_capacity instances [:, 0 ] = self . _max_capacity # The first item of each valid BPP instance is the capacity print ( capacities ) return list ( BPP ( items = instances [ i , 1 :], maximum_capacity = capacities [ i ]) for i in range ( len ( instances )) )

