ew knapsack problem from the given profit/weight data. Args: profits (Sequence[np.uint32] | np.ndarray): Profit associated with each item. weights (Sequence[np.uint32] | np.ndarray): Weight associated with each item. capacity (np.uint64, optional): Maximum total weight allowed in the knapsack. seed (Optional[int | np.random.SeedSequence], optional): Seed used to initialize the random generator. Raises: ValueError: If the profit and weight sequences do not have the same length or if the capacity is not positive. """ try : self . capacity = int ( capacity ) if self . capacity <= 0 : raise ValueError ( "capacity cannot be negative" ) except ( TypeError , ValueError ) as exc : raise ValueError ( f "invalid capacity ( { capacity } ) for Knapsack Problem" ) from exc if len ( profits ) != len ( weights ): raise ValueError ( f "Mismatch of weights and profits in Knapsack. " f " Got { len ( weights ) } weights and { len ( profits ) } profits." ) self . weights = np . asarray ( weights , dtype = np . uint32 ) self . profits = np . asarray ( profits , dtype = np . uint32 ) self . _penalization_factor = float ( penalty_factor ) super () . __init__ ( dimension = len ( profits ), bounds = [], name = "KP" , seed = seed ) def get_bounds_at ( self , i : int ) -> tuple : """Return the valid bounds for one decision variable. Each item is handled as a binary decision: selecting it corresponds to value 1, while leaving it out corresponds to value 0. Args: i (int): Index of the variable to inspect. Raises: IndexError: If the index is outside the valid range of the problem. Returns: tuple: A tuple containing the lower and upper bounds for the variable. """ if i < 0 or i > self . _dimension : raise IndexError ( f "Index { i } out-of-range. The bounds are 0- { self . _dimension } " ) return ( 0 , 1 ) @property def bounds ( self ): """Return the binary bounds for every decision variable in the problem.""" return list (( 0 , 1 ) for _ in range ( self . _dimension )) def evaluate ( self , individual : Sequence | Solution | np . ndarray ) -> Tuple [ float ]: """Evaluate a candidate solution and compute its objective value. The score is the total profit of the selected items minus a penalty for any excess weight beyond the knapsack capacity. This makes infeasible solutions receive a lower fitness than feasible ones. Args: individual (Sequence | Solution): Candidate solution to evaluate. Raises: ValueError: If the individual length does not match the number of items. Returns: Tuple[float]: A one-element tuple containing the objective value. """ if len ( individual ) != self . _dimension : raise ValueError ( f "Mismatch between individual dimension ( { len ( individual ) } ) " f "and Knapsack problem ( { self . _dimension } )" ) mask = np . asarray ( individual , dtype = bool ) profit = np . sum ( self . profits [ mask ], dtype = np . int32 ) packed = np . sum ( self . weights [ mask ], dtype = np . int32 ) difference = max ( 0 , packed - self . capacity ) penalty = self . _penalization_factor * difference profit -= penalty return ( profit ,) def __call__ ( self , individual : Sequence | Solution | np . ndarray ) -> Tuple [ float ]: """Evaluate a candidate solution and compute its objective value. The score is the total profit of the selected items minus a penalty for any excess weight beyond the knapsack capacity. This makes infeasible solutions receive a lower fitness than feasible ones. Args: individual (Sequence | Solution): Candidate solution to evaluate. Raises: ValueError: If the individual length does not match the number of items. Returns: Tuple[float]: A one-element tuple containing the objective value. """ return self . evaluate ( individual ) def __array__ ( self , dtype = np . uint32 , copy : Optional [ bool ] = None ) -> np . ndarray : """Return a NumPy array representation of the Knapsack Problem. The representation stores the capacity first and then alternates weight/profit pairs for each item, which is convenient for serialization and downstream processing. Returns: np.ndarray: A one-dimensional array describing the instance. """ return np . asarray ( [ self . capacity , * list ( itertools . chain . from_iterable ([ * zip ( self . weights , self . profits )]) ), ], dtype = dtype , copy = copy , ) def __str__ ( self ): """Return a compact string representation of the problem instance.""" return f "KP(n= { self . _dimension } ,C= { self . capacity } )" def __len__ ( self ): """Return the number of items defined by the problem.""" return len ( self . weights ) def create_solution ( self ) -> Solution : """Create a random initial solution for the Knapsack Problem. The returned solution is a binary vector that can be used as a starting point for an optimizer, although it may be infeasible if the selected items exceed the capacity. Returns: Solution: A solution object with binary decision variables and empty objectives (1d). """ chromosome = self . _rng . integers ( low = 0 , high = 1 , size = self . _dimension ) return Solution ( variables = chromosome , objectives = np . zeros ( 1 ), constraints = np . zeros ( 1 ) ) def to_file ( self , filename : str | Path = "instance.kp" ): """Stores the Knapsack Problem in a plain text file. The file format contains the number of items and the capacity on the first line, followed by one row per item containing its weight and profit. Args: filename (str | Path, optional): Destination file for the serialized instance. """ try : with open ( filename , "w" ) as file : file . write ( f " { len ( self ) } 	 { self . capacity } 

