so that repeated evaluations are fast. Args: number_of_nodes (int): Number of cities (nodes) in the instance. It must be a positive integer. coords (np.ndarray): A two-dimensional array of shape (N, 2) containing the x and y coordinates of each city. If a plain sequence is supplied it is automatically converted to a NumPy array. penalty_factor (np.float64 | float, optional): Penalisation factor used to lower the fitness of unfeasible solutions. Defaults to 10.0. matrix. Defaults to False. postpone_dist_comp (bool, optional): Boolean flag used to indicate that the distance matrix should not be precomputed. When True, distances are calculated on-the-fly in evaluate, rather than computing all the pairwise distances between nodes and creating a flattened 1D distance matrix. Defaults to False. save_distances_as_1d (bool, optional): Boolean flag to tell the problem that the distance matrix must be stored as a flattened 1d array using only the upper right triangular matrix. Defaults to False, and stores it as a 2d (number_of_nodes x number_of_nodes) matrix. seed (Optional[int | np.random.SeedSequence], optional): Seed used to initialise the internal random number generator, which is inherited from the parent ``Problem`` class. Defaults to None. Raises: ValueError: If ``coords`` does not have exactly two columns, i.e., its shape is not (N, 2). """ try : number_of_nodes = int ( number_of_nodes ) except ( TypeError , ValueError ) as exc : raise ValueError ( f "invalid number_of_nodes in TSP. Got: { number_of_nodes } " ) from exc try : if not isinstance ( coords , np . ndarray ): coords = np . asarray ( coords ) if coords . shape != ( number_of_nodes , 2 ): raise ValueError ( f "Expected coordinates shape to be ( { number_of_nodes } , 2). " f "Instead coords has the following shape: { coords . shape } ." ) self . _coordinates = np . asarray ( coords , dtype = np . float64 ) except ( TypeError , ValueError ) as exc : raise ValueError from exc try : self . _penalty_factor = float ( penalty_factor ) if self . _penalty_factor <= 0.0 : raise ValueError () except ( TypeError , ValueError ) as exc : raise ValueError ( "penalty_factor must be a valid positive float value. " f "Got { penalty_factor } . From: { exc } " ) from exc x_min , y_min = np . min ( self . _coordinates , axis = 0 ) x_max , y_max = np . max ( self . _coordinates , axis = 0 ) _bounds = list ((( x_min , y_min ), ( x_max , y_max )) for _ in range ( number_of_nodes )) super () . __init__ ( dimension = number_of_nodes , bounds = _bounds , name = "TSP" , seed = seed ) self . _distances = np . empty ( 1 ) if postpone_dist_comp : # If we postpone the computation of the distance # matrix, we're essentially working the same as # such matrix doesn't fit in memory self . _too_large_to_fit = True self . _saved_as_1d = False else : # This is a Symmetric TSP problem # we can store only the upper right triangular matrix try : self . _distances = cdist ( self . _coordinates , self . _coordinates ) self . _saved_as_1d = save_distances_as_1d if save_distances_as_1d : self . _saved_as_1d = True self . _distances = self . _distances [ np . triu_indices ( number_of_nodes , k = 1 ) ] self . _too_large_to_fit = False except Exception : # The distance matrix is too large to fit in memory # we keep the coordinates and compute the distances # on the fly each time self . _too_large_to_fit = True self . _saved_as_1d = False @property def coordinates ( self ) -> np . ndarray : return self . _coordinates @property def distances ( self ) -> np . ndarray : if self . _too_large_to_fit or self . _distances is None : warnings . warn ( "Distance matrix no calculated in TSP " f "for { self . dimension } nodes because it doesn't fit in memory or it was postponed." "Returning np.empty()" , RuntimeWarning , stacklevel = 2 , ) return np . empty ( 0 ) else : return self . _distances def evaluate ( self , individual : Sequence | Solution | np . ndarray ) -> Tuple [ float , ... ]: """Evaluate a candidate tour and compu