ray of shape (N, 2) containing the x and y coordinates of each city. If a plain sequence is supplied it is automatically converted to a NumPy array. penalty_factor (np.float64 | float, optional): Penalisation factor used to lower the fitness of unfeasible solutions. Defaults to 10.0. matrix. Defaults to False. postpone_dist_comp (bool, optional): Boolean flag used to indicate that the distance matrix should not be precomputed. When True, distances are calculated on-the-fly in evaluate, rather than computing all the pairwise distances between nodes and creating a flattened 1D distance matrix. Defaults to False. save_distances_as_1d (bool, optional): Boolean flag to tell the problem that the distance matrix must be stored as a flattened 1d array using only the upper right triangular matrix. Defaults to False, and stores it as a 2d (number_of_nodes x number_of_nodes) matrix. seed (Optional[int | np.random.SeedSequence], optional): Seed used to initialise the internal random number generator, which is inherited from the parent ``Problem`` class. Defaults to None. Raises: ValueError: If ``coords`` does not have exactly two columns, i.e., its shape is not (N, 2). """ try : number_of_nodes = int ( number_of_nodes ) except ( TypeError , ValueError ) as exc : raise ValueError ( f "invalid number_of_nodes in TSP. Got: { number_of_nodes } " ) from exc try : if not isinstance ( coords , np . ndarray ): coords = np . asarray ( coords ) if coords . shape != ( number_of_nodes , 2 ): raise ValueError ( f "Expected coordinates shape to be ( { number_of_nodes } , 2). " f "Instead coords has the following shape: { coords . shape } ." ) self . _coordinates = np . asarray ( coords , dtype = np . float64 ) except ( TypeError , ValueError ) as exc : raise ValueError from exc try : self . _penalty_factor = float ( penalty_factor ) if self . _penalty_factor <= 0.0 : raise ValueError () except ( TypeError , ValueError ) as exc : raise ValueError ( "penalty_factor must be a valid positive float value. " f "Got { penalty_factor } . From: { exc } " ) from exc x_min , y_min = np . min ( self . _coordinates , axis = 0 ) x_max , y_max = np . max ( self . _coordinates , axis = 0 ) _bounds = list ((( x_min , y_min ), ( x_max , y_max )) for _ in range ( number_of_nodes )) super () . __init__ ( dimension = number_of_nodes , bounds = _bounds , name = "TSP" , seed = seed ) self . _distances = np . empty ( 1 ) if postpone_dist_comp : # If we postpone the computation of the distance # matrix, we're essentially working the same as # such matrix doesn't fit in memory self . _too_large_to_fit = True self . _saved_as_1d = False else : # This is a Symmetric TSP problem # we can store only the upper right triangular matrix try : self . _distances = cdist ( self . _coordinates , self . _coordinates ) self . _saved_as_1d = save_distances_as_1d if save_distances_as_1d : self . _saved_as_1d = True self . _distances = self . _distances [ np . triu_indices ( number_of_nodes , k = 1 ) ] self . _too_large_to_fit = False except Exception : # The distance matrix is too large to fit in memory # we keep the coordinates and compute the distances # on the fly each time self . _too_large_to_fit = True self . _saved_as_1d = False @property def coordinates ( self ) -> np . ndarray : return self . _coordinates @property def distances ( self ) -> np . ndarray : if self . _too_large_to_fit or self . _distances is None : warnings . warn ( "Distance matrix no calculated in TSP " f "for { self . dimension } nodes because it doesn't fit in memory or it was postponed." "Returning np.empty()" , RuntimeWarning , stacklevel = 2 , ) return np . empty ( 0 ) else : return self . _distances def evaluate ( self , individual : Sequence | Solution | np . ndarray ) -> Tuple [ float , ... ]: """Evaluate a candidate tour and compute its objective value. The fitness of a feasible solution is the reciprocal of the total Euclidean tour length (``1.0 / distance``). This formulation turns the minimisation problem into a maximisation problem, which is consistent with the Digneapy framework's convention. Fitness, always to maximise. Infeasible tours—those that repeat cities are assigned a penalty proportional to the number of repetitions. If the supplied ``individual`` is a ``Solution`` object, its ``fitness``, ``objectives``, and ``constraints`` attributes are updated in-place. Args: individual (Sequence | Solution | np.ndarray): The candidate tour to evaluate. Must have length ``N``, where ``N`` is the number of cities or nodes. Raises: ValueError: If the length of ``individual`` does not equal ``N ``. Returns: Tuple[float, float]: A two-element tuple containing the objective value and the number of duplicated nodes in the inner tour. This second value should be zero for a feasible solution, meaning that all nodes are only visited once. """ if len ( individual ) != self . dimension : raise ValueError ( f "Mismatch between individual variables ( { len ( individual ) } )" f " and instance variables ( { self . dimension } ) in TSP. " f "A solution for the TSP must be a sequence of len { self . dimension } items. " f "Instead got { len ( individual ) } ." ) duplicated_count = len ( individual ) - len ( set ( individual )) # to_node shifts left by 1 to wrap the last node with the first one from_node = np . asarray ( individual ) to_node = np . roll ( np . asarray ( individual ), - 1 ) if self . _too_large_to_fit : from_coords = self . _coordinates [ from_node ] to_coords = self . _coordinates [ to_node ] distance = np . sum ( np . linalg . norm ( from_coords - to_coords , axis = 1 ), dtype = np . float64 ) else : if self . _saved_as_1d : # Now calculate from the flatted indices to extract # the distances from the flattened 1D distance matrix i = np . minimum ( from_node , to_node ) j = np . maximum ( from_node , to_node ) flat_indices = i * self . dimension - ( i * ( i + 1 )) // 2 + ( j - i - 1 ) distance = np . sum ( self . _distances [ flat_indices ], dtype = np . float64 ) else : distance = np . sum ( self . _distances [ from_node , to_node ], dtype = np . float64 ) if duplicated_count != 0 : penalty = np . float64 ( duplicated_count ) * distance * self . _penalty_factor fitness = 1.0 / ( distance + penalty ) else : fitness = 1.0 / distance try : # We assume that individual is a Solution object # and in that case we can update its attributes individual . fitness = fitness individual . objectives = ( fitness ,) individual . constraints = ( duplicated_count ,) except Exception : pass return ( fitness , duplicated_count ) def __call__ ( self , individual : Sequence | Solution | np . ndarray ) -> Tuple [ float , ... ]: """Evaluate a candidate tour and compute its objective value. Delegates directly to :meth:`evaluate`. This makes the problem instance callable, allowing it to be used wherever a plain function is expected (e.g. as an argument to a solver). Args: individual (Sequence | Solution | np.ndarray): The candidate tour to evaluate. Must have length ``N``. Returns: Tuple[float, float]: A two-element tuple containing the objective value and the number of duplicated nodes in the inner tour. This second value should be zero for a feasible solution, meaning that all nodes are only visited once. """ return self . evaluate ( individual ) def __str__ ( self ): return f "TSP(n= { self . dimension } )" def __len__ ( self ): return self . dimension def __array__ ( self , dtype = np . float64 , copy : Optional [ bool ] = None ) -> np . ndarray : """Return a NumPy array representation of the TSP instance. The returned array is the (N, 2) coordinate matrix, where each row stores the ``[x, y]`` position of one city. This is useful for serialisation and for passing the instance to downstream NumPy-based tools. Args: dtype: NumPy data type for the returned array. Defaults to ``np.float64``. copy (Optional[bool]): Whether to force a copy of the underlying data. Defaults to ``None``. Returns: npt.ndarray: The coordinate matrix of shape (N, 2). """ return np . asarray ( self . _coordinates , dtype = dtype , copy = copy ) def create_solution ( self , random : bool = False , start_node : int = 0 ) -> Solution : """Create a trivial initial solution for the TSP. The solution visits cities in natural order: 0 → 1 → 2 → … → N-1 → 0. This is a feasible but almost certainly non-optimal tour that can be used as a starting point for local search or population initialisation. Args: random(bool): If True, generate a random permutation of nodes instead of the natural-order tour. Defaults to False. start_node(int): Starting and endind node of the cyclic tour. Defaults to standard initial node (0). Returns: Solution: A ``Solution`` object whose ``variables`` encode the tour, with zeroed ``objectives`` and ``constraints`` arrays. """ items = np . zeros ( self . dimension , dtype = np . uint32 ) items [ 0 ] = start_node remaining_nodes = np . array ( [ c for c in range ( self . dimension ) if c != start_node ], dtype = np . uint32 ) if random : self . _rng . shuffle ( remaining_nodes ) items [ 1 :] = remaining_nodes fitness , duplicated = self . evaluate ( items ) return Solution ( variables = items , objectives = ( fitness ,), constraints = ( duplicated ,), fitness = fitness , ) def to_file ( self , filename : str | Path = "instance.tsp" ): """Serialise the TSP instance to a plain text file. The file will follow this format: - Line 1: number of cities. - Line 2: blank separator. - Lines3+: one city per line as ``x<TAB>y``. Args: filename (str | Path, optional): Destination path for the serialised instance. Defaults to ``"instance.tsp"``. Raises: RuntimeError: If something goes wrong. """ try : with open ( filename , "w" ) as file : file . write ( f " { len ( self ) } 

