 | Solution) -> bool: counter = Counter(individual) if any(counter[c] != 1 for c in counter if c != 0) or ( individual[0] != 0 or individual[-1] != 0 ): return False return True and def evaluate(self, individual: Sequence | Solution) -> tuple[float]: """Evaluates the candidate individual with the information of the Travelling Salesmas Problem. The fitness of the solution is the fraction of the sum of the distances of the tour Args: individual (Sequence | Solution): Individual to evaluate Returns: Tuple[float]: Fitness """ if len(individual) != self._nodes + 1: msg = f"Mismatch between individual variables ({len(individual)}) and instance variables ({self._nodes}) in {self.__class__.__name__}. A solution for the TSP must be a sequence of len {self._nodes + 1}" raise ValueError(msg) penalty: np.float64 = np.float64(0) if self.__evaluate_constraints(individual): distance: float = 0.0 for i in range(len(individual) - 2): distance += self._distances[individual[i]][individual[i + 1]] fitness = 1.0 / distance else: fitness = 2.938736e-39 # --> 1.0 / np.float.max penalty = np.finfo(np.float64).max if isinstance(individual, Solution): individual.fitness = fitness individual.objectives = (fitness,) individual.constraints = (penalty,) return (fitness,) def __call__(self, individual: Sequence | Solution) -> tuple[float]: return self.evaluate(individual) We must implement the method create_solution so we can initialise the algorithms solutions. def create_solution(self) -> Solution: items = [0] + list(range(1, self._nodes)) + [0] return Solution(chromosome=items) To cast the TSP problem to an actual evolvable instance we must define the to_instance method. In this example, the variables/chromosome of the Instance is the coordinates of the nodes. Note that for each domain, the chromosome of the instances must be adapted to the relevant information. def to_instance(self) -> Instance: return Instance(variables=self._coords.flatten()) Finally, the whole TSP class with several added 