mum ranges are greater than maximum ranges """ if dimension < 0: raise ValueError(f"Expected dimension > 0 got {dimension}") if len(x_range) != 2 or len(y_range) != 2: raise ValueError( f"Expected x_range and y_range to be a tuple with only to integers. Got: x_range = {x_range} and y_range = {y_range}" ) x_min, x_max = x_range y_min, y_max = y_range if x_min < 0 or x_max <= x_min: raise ValueError( f"Expected x_range to be (x_min, x_max) where x_min >= 0 and x_max > x_min. Got: x_range {x_range}" ) if y_min < 0 or y_max <= y_min: raise ValueError( f"Expected y_range to be (y_min, y_max) where y_min >= 0 and y_max > y_min. Got: y_range {y_range}" ) self._x_range = x_range self._y_range = y_range __bounds = [ (x_min, x_max) if i % 2 == 0 else (y_min, y_max) for i in range(dimension * 2) ] super().__init__(dimension=dimension, bounds=__bounds, name="TSP", seed=seed) The generate_instances method is quite similar to the create_solution in the Problem class. Basically, it creates a random instance with the characteristics defined in the domain. def generate_instances(self) -> Instance: """Generates a new instances for the TSP domain Returns: Instance: New randomly generated instance """ coords = self._rng.integers( low=(self._x_range[0], self._y_range[0]), high=(self._x_range[1], self._y_range[1]), size=(self.dimension, 2), dtype=int, ) coords = coords.flatten() return Instance(variables=coords) Likewise, the from_instance methods allows the domain to create an optimisation problem that can be solve using the definition of a particular instance. def from_instance(self, instance: Instance) -> TSP: n_nodes = len(instance) // 2 coords = tuple([*zip(instance[::2], instance[1::2])]) return TSP(nodes=n_nodes, coords=coords) Finally, the extract_features methods are domain and user depedent since the features to extract may vary from everyone needs. For this example the methods looks like: def extract_features(self, instance: Instance) -> tuple: """Extract the features of the instance based on the TSP domain. For the TSP the features are: - Size - Standard deviation of the distances - Centroid coordinates - Radius of the instance - Fraction of distinct instances - Rectangular area - Variance of the normalised nearest neighbours distances - Coefficient of variantion of the nearest neighbours distances - Cluster ratio - Mean cluster radius Args: instance (Instance): Instance to extract the features from Returns: Tuple[float]: Values of each feature """ tsp = self.from_instance(instance) xs = instance[0::2] ys = instance[1::2] area = (max(xs) - min(xs)) * (max(ys) - min(ys)) std_distances = np.std(tsp._distances) centroid = (np.mean(xs), np.mean(ys)) # (0.01 * np.sum(xs), 0.01 * np.sum(ys)) centroid_distance = [np.linalg.norm(city - centroid) for city in tsp._coords] radius = np.mean(centroid_distance) fraction = len(np.unique(tsp._distances)) / (len(tsp._distances) / 2) # Top five only norm_distances = np.sort(tsp._distances)[::-1][:5] / np.max(tsp._distances) variance_nnds = np.var(norm_distances) variation_nnds = variance_nnds / np.mean(norm_distances) dbscan = DBSCAN() dbscan.fit(tsp._coords) cluster_ratio = len(set(dbscan.labels_)) / self.dimension # Cluster radius mean_cluster_radius = 0.0 for label_id in dbscan.labels_: points_in_cluster = tsp._coords[dbscan.labels_ == label_id] cluster_centroid = ( np.mean(points_in_cluster[:, 0]), np.mean(points_in_cluster[:, 1]), ) mean_cluster_radius = np.mean( [np.linalg.norm(city - cluster_centroid) for city in tsp._coords] ) mean_cluster_radius /= len(set(dbscan.labels_)) return ( self.dimension, std_distances, centroid[0], centroid[1], radius, fraction, area, variance_nnds, variation_nnds, cluster_ratio, mean_cluster_radius, ) def extract_features_as_dict(self, instance: Instance) -> Mapping[str, float]: """Creates a dictionary with the features of the instance. The key are the names of each feature and the values are the values extracted from instance. Args: instance (Instance): Instance to extract the features from Returns: Mapping[str, float]: Dictionary with the names/values of each feature """ names = "size,std_distances,centroid_x,centroid_y,radius,fraction_distances,area,variance_nnNds,variation_nnNds,cluster_ratio,mean_cluster_radius" features = self.extract_features(instance) return {k: v for k, v in zip(names.split(","), features)} The complete TSPDomain class looks like: class TSPDomain(Domain): """Domain to generate instances for the Symmetric Travelling Salesman Problem.""" def __init__( self, dimension: int = 100, x_range: Tuple[int, int] = (0, 1000), y_range: Tuple[int, int] = (0, 1000), seed: int = 42, ): """Creates a new TSPDomain to generate instances for the Symmetric Travelling Salesman Problem Args: dimension (int, optional): Dimension of the instances to generate. Defaults to 100. x_range (Tuple[int, int], optional): Ranges for the Xs coordinates of each node/city. Defaults to (0, 1000). y_range (Tuple[int, int], optional): Ranges for the ys coordinates of each node/city. Defaults to (0, 1000). Raises: ValueError: If dimension is < 0 ValueError: If x_range OR y_range does not have 2 dimensions each ValueError: If minimum ranges are greater than maximum ranges """ if dimension < 0: raise ValueError(f"Expected dimension > 0 got {dimension}") if len(x_range) != 2 or len(y_range) != 2: raise ValueError( f"Expected x_range and y_range to be a tuple with only to integers. Got: x_range = {x_range} and y_range = {y_range}" ) x_min, x_max = x_range y_min, y_max = y_range if x_min < 0 or x_max <= x_min: raise ValueError( f"Expected x_range to be (x_min, x_max) where x_min >= 0 and x_max > x_min. Got: x_range {x_range}" ) if y_min < 0 or y_max <= y_min: raise ValueError( f"Expected y_range to be (y_min, y_max) where y_min >= 0 and y_max > y_min. Got: y_range {y_range}" ) self._x_range = x_range self._y_range = y_range __bounds = [ (x_min, x_max) if i % 2 == 0 else (y_min, y_max) for i in range(dimension * 2) ] super().__init__(dimension=dimens